package com.example.app.storage

import android.content.Context
import android.content.SharedPreferences
import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import java.security.KeyStore

/**
 * Secure storage manager using EncryptedSharedPreferences
 * All sensitive data is encrypted using AES256-GCM with hardware-backed keys
 */
class SecurePreferencesManager(private val context: Context) {

    companion object {
        private const val PREFS_FILENAME = "secure_user_prefs"
        private const val MASTER_KEY_ALIAS = "_androidx_security_master_key_"
    }

    // Initialize MasterKey with hardware-backed security
    private val masterKey: MasterKey by lazy {
        MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            // Require user authentication for key access
            .setUserAuthenticationRequired(
                false, // Set to true to require device unlock for access
                0
            )
            // Specify key purpose
            .setKeyGenParameterSpec(
                KeyGenParameterSpec.Builder(
                    MASTER_KEY_ALIAS,
                    KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
                )
                    .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
                    .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
                    .setKeySize(256)
                    // Require user authentication within last 30 seconds (optional)
                    // .setUserAuthenticationParameters(30, KeyProperties.AUTH_DEVICE_CREDENTIAL)
                    .build()
            )
            .build()
    }

    // EncryptedSharedPreferences instance
    private val encryptedPrefs: SharedPreferences by lazy {
        EncryptedSharedPreferences.create(
            context,
            PREFS_FILENAME,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    // ===== Secure Storage Methods =====

    /**
     * Store authentication token securely
     */
    fun saveAuthToken(token: String) {
        encryptedPrefs.edit()
            .putString("auth_token", token)
            .apply()
    }

    /**
     * Retrieve authentication token
     */
    fun getAuthToken(): String? {
        return encryptedPrefs.getString("auth_token", null)
    }

    /**
     * Store user credentials (only if absolutely necessary - prefer tokenized auth)
     */
    fun saveUserCredentials(email: String, hashedPassword: String) {
        encryptedPrefs.edit()
            .putString("user_email", email)
            .putString("password_hash", hashedPassword) // Already hashed on client
            .apply()
    }

    /**
     * Store sensitive user information
     */
    fun saveUserProfile(userId: String, fullName: String, phone: String) {
        encryptedPrefs.edit()
            .putString("user_id", userId)
            .putString("full_name", fullName)
            .putString("phone_number", phone)
            .apply()
    }

    /**
     * Store financial account information
     */
    fun saveAccountInfo(accountNumber: String, routingNumber: String) {
        encryptedPrefs.edit()
            .putString("account_number", accountNumber)
            .putString("routing_number", routingNumber)
            .apply()
    }

    /**
     * Retrieve account number
     */
    fun getAccountNumber(): String? {
        return encryptedPrefs.getString("account_number", null)
    }

    /**
     * Check if user is authenticated (has valid token)
     */
    fun isAuthenticated(): Boolean {
        return !getAuthToken().isNullOrEmpty()
    }

    /**
     * Secure logout - Clear all sensitive data
     */
    fun clearAllData() {
        encryptedPrefs.edit().clear().apply()

        // Optional: Also clear the master key from keystore
        // (Only do this if you want to force complete re-initialization)
        // clearMasterKey()
    }

    /**
     * Clear specific sensitive data
     */
    fun clearAuthData() {
        encryptedPrefs.edit()
            .remove("auth_token")
            .remove("password_hash")
            .apply()
    }

    /**
     * Delete master key from Android Keystore
     * WARNING: This will make all existing encrypted data unrecoverable
     */
    private fun clearMasterKey() {
        try {
            val keyStore = KeyStore.getInstance("AndroidKeyStore")
            keyStore.load(null)
            keyStore.deleteEntry(MASTER_KEY_ALIAS)
        } catch (e: Exception) {
            android.util.Log.e("SecurePrefs", "Error clearing master key", e)
        }
    }

    /**
     * Migrate data from legacy SharedPreferences to EncryptedSharedPreferences
     */
    fun migrateLegacyPreferences() {
        val legacyPrefs = context.getSharedPreferences("user_prefs", Context.MODE_PRIVATE)

        if (legacyPrefs.contains("auth_token")) {
            // Migrate sensitive data
            val authToken = legacyPrefs.getString("auth_token", null)
            val userEmail = legacyPrefs.getString("user_email", null)
            val accountNumber = legacyPrefs.getString("account_number", null)

            // Save to encrypted storage
            encryptedPrefs.edit().apply {
                authToken?.let { putString("auth_token", it) }
                userEmail?.let { putString("user_email", it) }
                accountNumber?.let { putString("account_number", it) }
                apply()
            }

            // Clear legacy storage
            legacyPrefs.edit()
                .remove("auth_token")
                .remove("user_email")
                .remove("account_number")
                .apply()

            android.util.Log.i("SecurePrefs", "Successfully migrated legacy preferences")
        }
    }

    /**
     * Check if EncryptedSharedPreferences is properly initialized
     */
    fun isSecureStorageAvailable(): Boolean {
        return try {
            // Test read/write operation
            encryptedPrefs.edit().putString("_test_key", "test_value").apply()
            val testValue = encryptedPrefs.getString("_test_key", null)
            encryptedPrefs.edit().remove("_test_key").apply()
            testValue == "test_value"
        } catch (e: Exception) {
            android.util.Log.e("SecurePrefs", "Secure storage not available", e)
            false
        }
    }
}

