import Foundation
import Security
import LocalAuthentication

/// Comprehensive Keychain manager for secure iOS data storage
/// Leverages Security framework with hardware-backed encryption
class KeychainManager {

    // MARK: - Keychain Configuration

    enum KeychainError: Error {
        case itemNotFound
        case duplicateItem
        case unexpectedStatus(OSStatus)
        case encodingError
        case decodingError
        case biometricAuthFailed
        case invalidData
    }

    /// Keychain accessibility levels
    /// Choose based on security vs. usability requirements
    enum AccessLevel {
        /// Data accessible only when device is unlocked
        /// Strongest security - data locked while device is locked
        case whenUnlocked

        /// Data accessible after first unlock
        /// Good balance - data available in background but protected on restart
        case afterFirstUnlock

        /// Data accessible with biometric authentication
        /// Maximum security - requires Face ID/Touch ID for each access
        case whenUnlockedBiometric

        /// Always accessible (NOT RECOMMENDED for sensitive data)
        /// Only use for non-sensitive data
        case always

        var rawValue: CFString {
            switch self {
            case .whenUnlocked:
                return kSecAttrAccessibleWhenUnlocked
            case .afterFirstUnlock:
                return kSecAttrAccessibleAfterFirstUnlock
            case .whenUnlockedBiometric:
                return kSecAttrAccessibleWhenUnlockedThisDeviceOnly
            case .always:
                return kSecAttrAccessibleAlways
            }
        }
    }

    // Singleton instance
    static let shared = KeychainManager()

    // Service identifier for keychain items
    private let serviceName: String
    private let accessGroup: String?

    private init(
        serviceName: String = Bundle.main.bundleIdentifier ?? "com.example.app",
        accessGroup: String? = nil
    ) {
        self.serviceName = serviceName
        self.accessGroup = accessGroup
    }

    // MARK: - Save Methods

    /// Save string value to keychain
    func save(
        _ value: String,
        forKey key: String,
        accessLevel: AccessLevel = .afterFirstUnlock,
        requireBiometric: Bool = false
    ) throws {
        guard let data = value.data(using: .utf8) else {
            throw KeychainError.encodingError
        }
        try save(data, forKey: key, accessLevel: accessLevel, requireBiometric: requireBiometric)
    }

    /// Save data to keychain with specified access level
    func save(
        _ data: Data,
        forKey key: String,
        accessLevel: AccessLevel = .afterFirstUnlock,
        requireBiometric: Bool = false
    ) throws {

        // Build keychain query
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecValueData as String: data,
            kSecAttrAccessible as String: accessLevel.rawValue
        ]

        // Add access group if specified (for keychain sharing between apps)
        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }

        // Add biometric authentication requirement
        if requireBiometric {
            let access = SecAccessControlCreateWithFlags(
                nil,
                accessLevel.rawValue,
                .userPresence, // Requires Touch ID/Face ID or passcode
                nil
            )
            query[kSecAttrAccessControl as String] = access
        }

        // Delete existing item first
        SecItemDelete(query as CFDictionary)

        // Add new item
        let status = SecItemAdd(query as CFDictionary, nil)

        guard status == errSecSuccess else {
            throw KeychainError.unexpectedStatus(status)
        }
    }

    /// Save Codable object to keychain
    func save<T: Codable>(
        _ object: T,
        forKey key: String,
        accessLevel: AccessLevel = .afterFirstUnlock
    ) throws {
        let encoder = JSONEncoder()
        let data = try encoder.encode(object)
        try save(data, forKey: key, accessLevel: accessLevel)
    }

    // MARK: - Retrieve Methods

    /// Retrieve string value from keychain
    func getString(forKey key: String, requireBiometric: Bool = false) throws -> String? {
        guard let data = try getData(forKey: key, requireBiometric: requireBiometric) else {
            return nil
        }
        return String(data: data, encoding: .utf8)
    }

    /// Retrieve data from keychain
    func getData(forKey key: String, requireBiometric: Bool = false) throws -> Data? {

        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }

        // Add biometric authentication requirement
        if requireBiometric {
            let context = LAContext()
            context.localizedReason = "Authenticate to access secure data"
            query[kSecUseAuthenticationContext as String] = context
        }

        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)

        if status == errSecItemNotFound {
            return nil
        }

        guard status == errSecSuccess else {
            throw KeychainError.unexpectedStatus(status)
        }

        guard let data = result as? Data else {
            throw KeychainError.invalidData
        }

        return data
    }

    /// Retrieve Codable object from keychain
    func getObject<T: Codable>(forKey key: String, as type: T.Type) throws -> T? {
        guard let data = try getData(forKey: key) else {
            return nil
        }
        let decoder = JSONDecoder()
        return try decoder.decode(type, from: data)
    }

    // MARK: - Delete Methods

    /// Delete specific keychain item
    func delete(forKey key: String) throws {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key
        ]

        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }

        let status = SecItemDelete(query as CFDictionary)

        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeychainError.unexpectedStatus(status)
        }
    }

    /// Delete all keychain items for this service
    func deleteAll() throws {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName
        ]

        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }

        let status = SecItemDelete(query as CFDictionary)

        guard status == errSecSuccess || status == errSecItemNotFound else {
            throw KeychainError.unexpectedStatus(status)
        }
    }

    // MARK: - Utility Methods

    /// Check if key exists in keychain
    func exists(forKey key: String) -> Bool {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecAttrAccount as String: key,
            kSecReturnData as String: false
        ]

        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }

        let status = SecItemCopyMatching(query as CFDictionary, nil)
        return status == errSecSuccess
    }

    /// List all keys in keychain
    func allKeys() throws -> [String] {
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: serviceName,
            kSecReturnAttributes as String: true,
            kSecMatchLimit as String: kSecMatchLimitAll
        ]

        if let accessGroup = accessGroup {
            query[kSecAttrAccessGroup as String] = accessGroup
        }

        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)

        if status == errSecItemNotFound {
            return []
        }

        guard status == errSecSuccess else {
            throw KeychainError.unexpectedStatus(status)
        }

        guard let items = result as? [[String: Any]] else {
            return []
        }

        return items.compactMap { $0[kSecAttrAccount as String] as? String }
    }
}

// MARK: - Convenience Extensions

extension KeychainManager {

    // Authentication Token Management
    func saveAuthToken(_ token: String) throws {
        try save(token, forKey: "auth_token", accessLevel: .afterFirstUnlock)
    }

    func getAuthToken() throws -> String? {
        return try getString(forKey: "auth_token")
    }

    func deleteAuthToken() throws {
        try delete(forKey: "auth_token")
    }

    // User Credentials (use only if absolutely necessary)
    func saveCredentials(email: String, password: String) throws {
        let credentials = ["email": email, "password": password]
        let data = try JSONSerialization.data(withJSONObject: credentials)
        try save(data, forKey: "user_credentials", accessLevel: .whenUnlocked, requireBiometric: true)
    }

    func getCredentials() throws -> (email: String, password: String)? {
        guard let data = try getData(forKey: "user_credentials", requireBiometric: true),
              let credentials = try JSONSerialization.jsonObject(with: data) as? [String: String],
              let email = credentials["email"],
              let password = credentials["password"] else {
            return nil
        }
        return (email, password)
    }

    // Biometric Token Storage
    func saveBiometricToken(_ token: String) throws {
        try save(token, forKey: "biometric_token", accessLevel: .whenUnlockedBiometric, requireBiometric: true)
    }

    func getBiometricToken() throws -> String? {
        return try getString(forKey: "biometric_token", requireBiometric: true)
    }
}

