// MARK: - Migration from UserDefaults

extension KeychainManager {

    /// Migrate sensitive data from UserDefaults to Keychain
    func migrateFromUserDefaults() {
        let userDefaults = UserDefaults.standard

        // Migrate auth token
        if let authToken = userDefaults.string(forKey: "auth_token") {
            try? saveAuthToken(authToken)
            userDefaults.removeObject(forKey: "auth_token")
        }

        // Migrate user email
        if let email = userDefaults.string(forKey: "user_email") {
            try? save(email, forKey: "user_email")
            userDefaults.removeObject(forKey: "user_email")
        }

        // Migrate account number
        if let accountNumber = userDefaults.string(forKey: "account_number") {
            try? save(accountNumber, forKey: "account_number", accessLevel: .whenUnlocked)
            userDefaults.removeObject(forKey: "account_number")
        }

        userDefaults.synchronize()
        print("Migration from UserDefaults completed")
    }
}

// MARK: - Security Best Practices

/*
1. Access Level Selection:
   - .whenUnlocked: Maximum security, data unavailable when locked
   - .afterFirstUnlock: Good balance, allows background access
   - .whenUnlockedBiometric: Maximum security + biometric requirement
   - .always: AVOID for sensitive data

2. Biometric Authentication:
   - Use requireBiometric: true for highly sensitive data
   - Provides additional security layer beyond device unlock

3. Data Classification:
   - Authentication tokens: .afterFirstUnlock
   - Passwords: .whenUnlocked + biometric
   - Payment info: .whenUnlocked + biometric
   - Account numbers: .whenUnlocked
   - Non-sensitive preferences: UserDefaults (not Keychain)

4. Error Handling:
   - Always handle KeychainError cases
   - Implement fallback strategies for biometric failures
   - Log security events for monitoring

5. Testing:
   - Test on physical devices (Keychain behaves differently on simulator)
   - Test device lock/unlock scenarios
   - Test biometric success/failure cases
   - Test app reinstall (Keychain persists by default)
*/

