// MARK: - Database Entities

@Entity(tableName = "users")
data class User(
    @PrimaryKey val userId: String,
    @ColumnInfo(name = "email") val email: String,
    @ColumnInfo(name = "full_name") val fullName: String,
    @ColumnInfo(name = "phone_number") val phoneNumber: String,
    @ColumnInfo(name = "account_number") val accountNumber: String,
    @ColumnInfo(name = "created_at") val createdAt: Long
)

@Entity(tableName = "transactions")
data class Transaction(
    @PrimaryKey(autoGenerate = true) val transactionId: Long = 0,
    @ColumnInfo(name = "user_id") val userId: String,
    @ColumnInfo(name = "amount") val amount: Double,
    @ColumnInfo(name = "recipient") val recipient: String,
    @ColumnInfo(name = "recipient_account") val recipientAccount: String,
    @ColumnInfo(name = "timestamp") val timestamp: Long,
    @ColumnInfo(name = "memo") val memo: String?
)

// MARK: - DAOs

@Dao
interface UserDao {
    @Query("SELECT * FROM users WHERE userId = :userId")
    suspend fun getUser(userId: String): User?

    @Insert(onConflict = OnConflictStrategy.REPLACE)
    suspend fun insertUser(user: User)

    @Query("DELETE FROM users")
    suspend fun deleteAll()
}

@Dao
interface TransactionDao {
    @Query("SELECT * FROM transactions WHERE user_id = :userId ORDER BY timestamp DESC")
    suspend fun getTransactions(userId: String): List<Transaction>

    @Insert
    suspend fun insertTransaction(transaction: Transaction)

    @Query("DELETE FROM transactions WHERE user_id = :userId")
    suspend fun deleteUserTransactions(userId: String)
}

// MARK: - Encrypted Database

@Database(
    entities = [User::class, Transaction::class],
    version = 1,
    exportSchema = false
)
abstract class AppDatabase : RoomDatabase() {
    abstract fun userDao(): UserDao
    abstract fun transactionDao(): TransactionDao

    companion object {
        @Volatile
        private var INSTANCE: AppDatabase? = null

        fun getInstance(context: Context): AppDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = buildEncryptedDatabase(context)
                INSTANCE = instance
                instance
            }
        }

        /**
         * Build Room database with SQLCipher encryption
         */
        private fun buildEncryptedDatabase(context: Context): AppDatabase {
            // Get or generate encryption key
            val encryptionKey = DatabaseKeyManager.getOrCreateDatabaseKey(context)

            // Create SQLCipher support factory
            val factory = SupportFactory(SQLiteDatabase.getBytes(encryptionKey.toCharArray()))

            return Room.databaseBuilder(
                context.applicationContext,
                AppDatabase::class.java,
                "secure_app_database"
            )
                .openHelperFactory(factory) // Enable SQLCipher encryption
                .fallbackToDestructiveMigration() // For development; use proper migrations in production
                .build()
        }

        /**
         * Close and clear database instance
         */
        fun closeDatabase() {
            INSTANCE?.close()
            INSTANCE = null
        }
    }
}

