/**
 * Manages database encryption keys using Android Keystore
 */
object DatabaseKeyManager {

    private const val KEY_ALIAS = "database_encryption_key"
    private const val PREFS_NAME = "secure_db_prefs"
    private const val KEY_DB_KEY = "db_key"

    /**
     * Get existing database key or create a new one
     */
    fun getOrCreateDatabaseKey(context: Context): String {
        val encryptedPrefs = getEncryptedPreferences(context)

        // Try to retrieve existing key
        var dbKey = encryptedPrefs.getString(KEY_DB_KEY, null)

        if (dbKey == null) {
            // Generate new key
            dbKey = generateDatabaseKey()
            // Store in encrypted preferences
            encryptedPrefs.edit()
                .putString(KEY_DB_KEY, dbKey)
                .apply()
        }

        return dbKey
    }

    /**
     * Generate a secure random database encryption key
     */
    private fun generateDatabaseKey(): String {
        // Generate 256-bit (32-byte) key
        val keyGenerator = KeyGenerator.getInstance("AES")
        keyGenerator.init(256, SecureRandom())
        val key = keyGenerator.generateKey()

        // Convert to hex string
        return key.encoded.joinToString("") { "%02x".format(it) }
    }

    /**
     * Get EncryptedSharedPreferences for key storage
     */
    private fun getEncryptedPreferences(context: Context): android.content.SharedPreferences {
        val masterKey = MasterKey.Builder(context)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()

        return EncryptedSharedPreferences.create(
            context,
            PREFS_NAME,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    /**
     * Rotate database encryption key (advanced use case)
